{"content": "     1|import { readdirSync } from 'fs'
     2|import { join } from 'path'
     3|import { loadPageData } from '@/lib/page-data'
     4|import SectionsRenderer from '@/components/SectionsRenderer'
     5|import type { Metadata } from 'next'
     6|import { LOCALES } from '@/lib/locales'
     7|
     8|interface Props { params: Promise<{ locale: string; slug: string }> }
     9|
    10|export function generateStaticParams() {
    11|  const pages = readdirSync(join(process.cwd(), 'nexa-pages'))
    12|    .filter(f => f.endsWith('.json'))
    13|    .map(f => f.replace('.json', ''))
    14|  const params: { locale: string; slug: string }[] = []
    15|  for (const locale of LOCALES) {
    16|    for (const slug of pages) {
    17|      params.push({ locale, slug })
    18|    }
    19|  }
    20|  return params
    21|}
    22|
    23|export async function generateMetadata({ params }: Props): Promise<Metadata> {
    24|  const { locale, slug } = await params
    25|  const data = loadPageData(locale, slug)
    26|  if (!data) return {}
    27|  return { title: data.pageConfig?.title || 'Nexa Paraguay', alternates: { languages: { es: `/es/${slug}`, en: `/en/${slug}`, nl: `/nl/${slug}`, de: `/de/${slug}` } } }
    28|}
    29|
    30|export default async function Page({ params }: Props) {
    31|  const { locale, slug } = await params
    32|  const data = loadPageData(locale, slug)
    33|  if (!data) return <div className="text-center p-16 text-text-muted">Not found</div>
    34|  return <SectionsRenderer content={data.content} pageConfig={data.pageConfig} images={data.images.images} locale={data.locale} />
    35|}
